I don't think this needs to be a `useRef`, we could just have it be a `useState` and set something like this:

```
const [subscribers, setSubscribers] = useState<Record<string, (config: AIOnboardingSource | null) => void>>({});

const subscribeToSourceConfigChanges = useCallback((callback, opts) => {
 const subscriptionId = crypto.randomUUID();
 setSubscribers(prev => ({ ...prev, [subscriptionId]: callback }));

 if (opts?.sendMessageOnSubscribe) {
 callback(sourceConfig ?? null);
 }
 return subscriptionId;
}, [sourceConfig]);

const unsubscribeFromSourceConfigChanges = useCallback((subscriptionId: string) => {
 setSubscribers(prev => {
 const { [subscriptionId]: _, ...rest } = prev;
 return rest;
 });
}, []);
```

