```ts
const buildPeopleRequestBody = ({
 workspaceId,
 conversationId,
 previewActionTaskId,
 actionSourceSettings,
 inputs,
}: {
 workspaceId: string;
 conversationId?: string;
 previewActionTaskId?: string;
 actionSourceSettings: ActionSourceSettings | undefined;
 inputs: Record<string, unknown>;
}): CreateCPJTableBody => {
 if (!actionSourceSettings || !actionSourceSettings.previewActionKey) {
 throw new Error('No action source settings found');
 }

 return {
 workspaceId,
 tableName: 'People Search',
 workbookId: null,
 conversationId,
