 },
 clientSettings: {
 sourceTableOutputs: actionSourceSettings.sourceTableOutputs,
 tableType: actionSourceSettings.tableType,
 },
 basicFields: basicFieldsPeople(true),
 previewActionTaskId,
 },
 };
};
